const embeddingResponse = $json;
const parseDecision = $('Parse CEO Decision').first().json;

const embeddingValues = embeddingResponse?.embedding?.values || [];

if (embeddingValues.length === 0) {
  throw new Error('Embedding vazio. Resposta da API: ' + JSON.stringify(embeddingResponse).substring(0, 300));
}

const embeddingStr = '[' + embeddingValues.join(',') + ']';

const content = 'C-Suite Meeting — ' + parseDecision.runTimestamp + '\n\nResumo Executivo: ' + parseDecision.summaryText + '\n\nDecisoes: ' + JSON.stringify(parseDecision.decisoes || []);

const metadata = {
  runTimestamp: parseDecision.runTimestamp,
  issueTitle: parseDecision.issueTitle,
  type: 'csuite_meeting',
  embeddingDimensions: embeddingValues.length
};

return [{ json: { content, metadata: JSON.stringify(metadata), embeddingStr } }];

const compiledReport = $input.first().json.compiledReport || '';
const context = $input.first().json.context || '';
const maxContext = 6000;
const contextTruncated = context.length > maxContext
  ? context.substring(0, maxContext) + '\n[... contexto truncado]'
  : context;

const ceoRequestBody = {
  contents: [{
    role: 'user',
    parts: [{
      text: 'Voce acaba de receber os relatorios de todo o C-Suite. Sintetize as analises e tome as decisoes estrategicas.\n\n' + compiledReport + '\n\n---\nCONTEXTO (resumido):\n' + contextTruncated
    }]
  }],
  systemInstruction: {
    parts: [{
      text: 'Voce e Andy Grove (Grove), CEO da Adventure Labs, uma Assessoria Martech brasileira. Seu time e: Rodrigo Ribas (Founder/DG), Igor Ribas (Designer), Mateus Scopel (Gestor de Trafego Jr). Voce acabou de receber os relatorios do CFO (Buffett), CTO (Torvalds), COO (Ohno), CMO (Ogilvy) e CPO (Cagan). Sintetize tudo e decida as 1 a 3 acoes mais impactantes para as proximas 48-96 horas. Seja objetivo, estrategico e orientado a execucao. Inclua cultura bottom-up: identifique oportunidades de melhoria que os C-levels possam ter perdido. Responda OBRIGATORIAMENTE em JSON valido com as chaves: resumo_executivo (string de 3-5 frases), decisoes (array de objetos com acao, responsavel, prazo e motivo), titulo_issue_github (string concisa para o titulo da issue principal no GitHub — max 80 chars), descricao_issue_github (string em Markdown com contexto da decisao, acoes e criterios de aceite — use ## para subsecoes), mensagem_google_chat (string para notificacao no Google Chat — max 300 chars, inclua emoji e seja direto).'
    }]
  },
  generationConfig: {
    temperature: 0.5,
    maxOutputTokens: 8192,
    responseMimeType: 'application/json'
  }
};

return [{ json: { ...$input.first().json, ceoRequestBody } }];
